public synchronized String encrypt(String plaintext) throws Exception {
    MessageDigest md = null;
    try {
        md = MessageDigest.getInstance("MD5");
    } catch (Exception e) {
    }
    try {
        md.update(plaintext.getBytes("UTF-8"));
    } catch (Exception e) {
    }
    byte raw[] = md.digest();
    String hash = (new BASE64Encoder()).encode(raw);
    return hash;
}

