            if (conn != null) conn.rollback(); else System.out.println("ERROR: No es pot fer rollback sense connexió!");
        } catch (Exception ex) {
            System.out.println("Error: " + e.getMessage());
            ex.printStackTrace();
        }
    } finally {
        ToolsBD.closeConn(conn, ps, null);
    }
    return visado;
}

