public static final String calculate(File f) {
    MessageDigest md;
    BufferedReader rd;
    StringBuffer buffer = new StringBuffer("");
    try {
        rd = new BufferedReader(new FileReader(f));
        md = MessageDigest.getInstance("SHA");
        String line = "";
        while ((line = rd.readLine()) != null) buffer.append(line);
