        File[] sources = Source(argv[0]);
        if (null != sources) {
            for (File src : sources) {
                File[] targets = Target(src, argv);
                if (null != targets) {
                    final long srclen = src.length();
                    try {
                        FileChannel source = new FileInputStream(src).getChannel();
                        try {
                            for (File tgt : targets) {
