    logger.debug("[headers]");
    for (Entry<String, List<String>> header : httpURLConnection.getHeaderFields().entrySet()) {
        if (header.getKey() != null) {
            for (String value : header.getValue()) {
                if (value != null) {
                    logger.debug(header.getKey() + ": " + value);
