        con.setAutoCommit(false);
        con.rollback();
        assertEquals(1, stmt.executeUpdate("insert into #testAutoCommit (i) values (1)"));
        con.setAutoCommit(true);
        con.setAutoCommit(false);
        con.rollback();
        con.setAutoCommit(true);
        ResultSet rs = stmt.executeQuery("select i from #testAutoCommit");
        assertTrue(rs.next());
