                    while ((sizeRead = dis.read(b)) > -1) {
                        fos.write(b, 0, sizeRead);
                        totalSizeRead += sizeRead;
                        photo.addToProcessedSize(sizeRead);
                        photo.setTotalProcessedSize(totalSizeRead);
                        photo.setTotalProcessedNumber(totalNumberRead);
                        publish(photo);
