                            File clefsFile = new File(databases, currentName + "_clefs");
                            clefsFile.createNewFile();
                            ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(clefsFile));
                            oos.writeObject(clefs);
                            oos.close();
